@page "/category/{Slug}"

<PageTitle>@GetCategoryName() - RecipeHub</PageTitle>

<h1>@GetCategoryName()</h1>
<p><a href="categories">&larr; Back to all categories</a></p>

<div class="row">
    @foreach (var recipe in GetRecipes())
    {
        <div class="col-md-6 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text">@recipe.Summary</p>
                    <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter]
    public string Slug { get; set; } = "";

    private string GetCategoryName() => Slug switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        "baking" => "🍞 Baking",
        "beverages" => "🥤 Beverages",
        "vegetarian" => "🥬 Vegetarian",
        _ => "Recipes"
    };

    private List<RecipeInfo> GetRecipes() => Slug switch
    {
        "appetizers" => new()
        {
            new(1, "Bruschetta", "Classic Italian tomato and basil bruschetta."),
            new(2, "Stuffed Mushrooms", "Cheese-stuffed mushrooms baked to perfection.")
        },
        "main-courses" => new()
        {
            new(3, "Spaghetti Carbonara", "Creamy Roman pasta with pancetta and egg."),
            new(4, "Grilled Salmon", "Fresh salmon with lemon herb butter.")
        },
        "desserts" => new()
        {
            new(5, "Chocolate Lava Cake", "Rich molten chocolate cake with a gooey center."),
            new(6, "Tiramisu", "Classic Italian coffee-flavored dessert.")
        },
        "baking" => new()
        {
            new(7, "Sourdough Bread", "Artisan sourdough with a crispy crust."),
            new(8, "Cinnamon Rolls", "Soft rolls with cinnamon sugar and cream cheese frosting.")
        },
        "beverages" => new()
        {
            new(9, "Mango Smoothie", "Tropical mango smoothie with yogurt."),
            new(10, "Iced Matcha Latte", "Creamy iced matcha green tea latte.")
        },
        "vegetarian" => new()
        {
            new(11, "Vegetable Stir-Fry", "Colorful veggies in a savory sauce."),
            new(12, "Caprese Salad", "Fresh mozzarella, tomatoes, and basil.")
        },
        _ => new()
    };

    private record RecipeInfo(int Id, string Title, string Summary);
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (isSubmitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been submitted for review.</p>
        <button class="btn btn-primary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Model.Ingredients" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps" />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool isSubmitted;

    private void HandleSubmit()
    {
        isSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new();
        isSubmitted = false;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = "";
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var starValue = i;
        <span class="star @(starValue <= currentRating ? "filled" : "")"
              @onclick="() => Rate(starValue)"
              @onmouseover="() => hoverRating = starValue"
              @onmouseout="() => hoverRating = 0"
              style="cursor: pointer; font-size: 1.5rem; color: @(starValue <= (hoverRating > 0 ? hoverRating : currentRating) ? "#ffc107" : "#e0e0e0");">
            ★
        </span>
    }
    @if (currentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @currentRating out of 5 stars</span>
    }
    else
    {
        <span class="ms-2 text-muted">Click to rate</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int currentRating;
    private int hoverRating;

    private void Rate(int rating)
    {
        currentRating = rating;
    }
}

